<div class="card admin-stats-card"><h2>管理后台</h2><div class="admin-stats-grid"><div class="stat"><p class="muted">总用户</p><b><?=$total?></b></div><div class="stat"><p class="muted">启用账号</p><b><?=$active?></b></div><div class="stat"><p class="muted">已到期</p><b><?=$exp?></b></div></div></div><div class="card"><div class="admin-list-head"><h3>用户列表</h3><div class="admin-toolbar"><a class="btn light compact" href="index.php?r=admin_register_settings">注册设置</a><a class="btn light compact" href="index.php?r=admin_yh_oauth">授权登录</a><a class="btn light compact" href="index.php?r=admin_proxy">代理设置</a><a class="btn green compact" href="index.php?r=admin_create">新增用户</a></div></div><form method="get" class="actions" style="margin:12px 0"><input type="hidden" name="r" value="admin"><input style="max-width:320px" name="q" value="<?=h($q)?>" placeholder="搜索用户名"><button class="btn">搜索</button><a class="btn light" href="index.php?r=admin">重置</a></form><div class="table-wrap"><table><thead><tr><th>ID</th><th>用户名</th><th>角色</th><th>状态</th><th>有效期</th><th>注册时间</th><th>最后登录</th><th>操作</th></tr></thead><tbody><?php foreach($users as $x): $expired=$x['role']!=='admin'&&StepSystem\Core\Auth::expired($x['expires_at']);?><tr><td><?=h($x['id'])?></td><td><?=h($x['username'])?></td><td><?=h($x['role'])?></td><td><?=((int)$x['status']===1)?'<span class="badge ok">启用</span>':'<span class="badge bad">禁用</span>'?></td><td><?=$x['role']==='admin'?'<span class="badge ok">永久</span>':($expired?'<span class="badge bad">'.h($x['expires_at']).'</span>':'<span class="badge ok">'.h($x['expires_at']?:'未设置').'</span>')?></td><td><?=h($x['created_at'])?></td><td><?=h($x['last_login_at']?:'-')?></td><td><div class="user-row-actions"><a class="btn light compact" href="index.php?r=admin_edit&id=<?=$x['id']?>">编辑</a><a class="btn light compact" href="index.php?r=admin_user_logs&id=<?=$x['id']?>">日志</a><?php if($x['role']!=='admin'): ?><form method="post" action="index.php?r=admin_delete" class="inline-delete" onsubmit="return confirm('确定删除？')"><input type="hidden" name="csrf_token" value="<?=h($_SESSION['csrf_token']??'')?>"><input type="hidden" name="id" value="<?=h($x['id'])?>"><button class="btn red compact" type="submit">删除</button></form><?php endif; ?></div></td></tr><?php endforeach; ?></tbody></table></div><div class="actions" style="justify-content:center;margin-top:16px"><?php if($page>1): ?><a class="btn light" href="index.php?r=admin&q=<?=urlencode($q)?>&page=<?=$page-1?>">上一页</a><?php endif; ?><span class="btn gray">第 <?=$page?> / <?=$pages?> 页</span><?php if($page<$pages): ?><a class="btn light" href="index.php?r=admin&q=<?=urlencode($q)?>&page=<?=$page+1?>">下一页</a><?php endif; ?></div></div>